#include<bits/stdc++.h>
using namespace std;
long long p[100010];
long long n,m;
struct segment_tree
{
    struct node
    {
        long long l,r,min1,val;
        long long lson,rson;
        long long tag;
    }a[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].min1=min(a[a[x].lson].min1,a[a[x].rson].min1);
        a[x].val=min(a[a[x].lson].val,a[a[x].rson].val);
    }
    void pushdown(long long x)
    {
        long long mid=(a[x].l+a[x].r)>>1;
        long long ls=a[x].lson,rs=a[x].rson;
        long long tg=a[x].tag;
        if(tg==-1)
        {
            return;
        }
        a[ls].min1=tg;
        a[rs].min1=tg;
        if(tg==n+1)
        {
            a[ls].val=2e9;
            a[rs].val=2e9;
        }
        else
        {
            a[ls].val=p[tg]-p[a[ls].r];
            a[rs].val=p[tg]-p[a[rs].r];
        }
        a[ls].tag=tg;
        a[rs].tag=tg;
        a[x].tag=-1;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        a[x].tag=-1;
        if(l==r)
        {
            a[x].min1=l;
            a[x].val=0;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l||l>r)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].min1=z;
            if(z==n+1)
            {
                a[x].val=2e9;
            }
            else
            {
                a[x].val=p[z]-p[a[x].r];
            }
            a[x].tag=z;
            return;
        }
        pushdown(x);
        update(a[x].lson,l,r,z);
        update(a[x].rson,l,r,z);
        pushup(x);
    }
    long long getmin(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 2e9;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].min1;
        }
        pushdown(x);
        return min(getmin(a[x].lson,l,r),getmin(a[x].rson,l,r));
    }
    long long getval(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l||l>r)
        {
            return 2e9;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].val;
        }
        pushdown(x);
        return min(getval(a[x].lson,l,r),getval(a[x].rson,l,r));
    }
    long long query(long long x,long long v)
    {
        if(a[x].min1>v)
        {
            return -1;
        }
        if(a[x].l==a[x].r)
        {
            return a[x].l;
        }
        pushdown(x);
        if(a[a[x].rson].min1<=v)
        {
            return query(a[x].rson,v);
        }
        else
        {
            return query(a[x].lson,v);
        }
    }
}t;
int main()
{
    long long T;
    scanf("%lld",&T);
    while(T--)
    {
        scanf("%lld%lld",&n,&m);
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld",&p[i]);
        }
        t.cnt=0;
        t.init(1,n);
        while(m--)
        {
            long long op,x,y;
            scanf("%lld%lld%lld",&op,&x,&y);
            if(op==1)
            {
                long long l=x,r=y,best=min(y,t.query(1,y+1));
                t.update(1,x,best,y+1);
            }
            else
            {
                long long l=1,r=x,best=min(x,t.query(1,y));
                long long ans=2e9;
                if(best!=-1)
                {
                    ans=p[y]-p[best];
                }
                ans=min(ans,t.getval(1,best+1,x));
                if(ans>1e9)
                {
                    ans=-1;
                }
                printf("%lld\n",ans);
            }
        }
    }
    return 0;
}
